// Features Component

import { Link } from 'react-router-dom';

function Features() {
    const features = [
        {

            title: 'HOA violation Issues',
            description: 'HOA violation Issues',
            location: '/AppDemos'
        },
        {

            title: 'Evidence photos',
            description: 'Evidence photos',
            location: '/Developments'
        },
        {

            title: 'Evidence Video',
            description: 'Evidence Video',
            location: '/Programming'
        }
    ];
    const handleButtonClickToTop = () => {
        window.scrollTo({
            top: 0,
            behavior: 'smooth'
        });
    }
    return (
        <section className="features">
            {features.map((feature, index) => (
                <div key={index} className="card">

                    <h3>{feature.title}</h3>
                    <p>{feature.description}</p>
                    <div> <Link to={feature.location}>
                        <button onClick={handleButtonClickToTop}>Go</button>
                    </Link></div>

                </div>
            ))}
        </section>
    );
}

export default Features;