import React, { useState } from 'react';
import YouTubePlayer from './displayUtubeembed';
import './Programming.css';
import { useNavigate } from 'react-router-dom';

const Programminggroup = () => {

    const navigate = useNavigate();
    const handleButtonClickHOA = () => {
        navigate('/ProgrammingHOA');
        window.scrollTo({
            top: 20,
            behavior: 'smooth'
        });
    };
    const handleButtonClicklynn = () => {
        navigate('/Programminglynn');
        window.scrollTo({
            top: 20,
            behavior: 'smooth'
        });
    };
    const handleButtonClickQin = () => {
        navigate('/ProgrammingQin');
        window.scrollTo({
            top: 20,
            behavior: 'smooth'
        });
    };
    const handleButtonClickMyfamily = () => {
        navigate('/ProgrammingMyfamily');
        window.scrollTo({
            top: 20,
            behavior: 'smooth'
        });
    };

    return (
        <div>

            <ul><li>   <button className="btn" onClick={handleButtonClickHOA}>Complaints HOA</button></li>
                <li>   <button className="btn" onClick={handleButtonClicklynn}>Complaints Lynn</button></li>
                <li>   <button className="btn" onClick={handleButtonClickQin}>Complaints HOA's president</button></li>
                <li>   <button className="btn" onClick={handleButtonClickMyfamily}>My beautiful American family</button></li>

            </ul>
        </div>
    );
};


export default Programminggroup;

