
import { useNavigate } from 'react-router-dom';

import './Hero.css';


function Hero() {
    const navigate = useNavigate();
    const handleButtonClick = () => {
        navigate('/');
        window.scrollTo({
            top: 0,
            behavior: 'smooth'
        });
    };

    return (
        <section className="hero">
            <h1>Welcome to Edward Chen and his family home.</h1>
            <p>we collected the evidence and fight for the justice</p>
            <button className="btn" onClick={handleButtonClick}>Get Started</button>


        </section>
    );
}

export default Hero;