
import { useParams } from 'react-router-dom';

function UserProfile() {
    const { userId } = useParams();

    return (
        <div style={{ padding: '2rem', textAlign: 'left' }}>
            <h1>User Profile</h1>
            <p>Viewing profile for user ID: <strong>{userId}</strong></p>

            <div style={{
                background: '#f8f9fa',
                padding: '2rem',
                borderRadius: '8px',
                marginTop: '2rem',
                maxWidth: '400px',
                margin: '2rem auto'
            }}>
                <h2>Myself</h2>
                <p>Name: Guo Hua Chen</p>
                <p>career: Web developer and graphic designer</p>
                <p>Language: Cantonese, Manderin, English</p>
            </div>
        </div>
    );
}

export default UserProfile;